def parse_tag(raw_tag) do
  case is_binary(raw_tag) && Enum.reverse(String.split(raw_tag, ".")) do
    [format | tag] when format in ["rss", "atom"] -> {format, Enum.join(tag, ".")}
    _ -> {"atom", raw_tag}
  end
end

